mapper.select:
SELECT c.id, c.community_name, c.community_code, c.address, c.district_id, d.district_name, c.phone, c.property_company, c.area, c.status, c.remark, c.create_time, c.update_time, (SELECT COUNT(*) FROM bs_house h INNER JOIN bs_unit u ON h.unit_id = u.id AND u.del_flag = 0 INNER JOIN bs_building b ON u.building_id = b.id AND b.del_flag = 0 WHERE b.community_id = c.id AND h.del_flag = 0 ) AS house_count FROM bs_community c LEFT JOIN bs_district d ON c.district_id = d.id WHERE c.del_flag = 0
AND c.community_name LIKE CONCAT('%', #{query.communityName}, '%')
AND c.community_code LIKE CONCAT('%', #{query.communityCode}, '%')
AND c.district_id = #{query.districtId}
AND c.status = #{query.status}
ORDER BY c.create_time DESC
